import React from "react";
import "../styles/About.css";
import aboutImg from "../img/about.jpg";

export default function About() {
  return (
    <div className="about-us">
      <img alt="" src={aboutImg} className="about-us-img" />
      <div className="about-us-txt">
        <div className="about-heading">About Society Associates</div>
        <p className="about-txt">
          We, Society Associates, operating from Kalyan, Maharashtra, are a
          multidisciplinary team of accounting and audit professionals with
          profound experience. We offer a scope of administrations to meet the
          complex and evolving accounting, book-keeping and auditing challenges
          that you may face on various fronts. Our mission is to give clients
          'The Best Accounting & Auditing Solutions' for their organizations,
          societies and monetary and administrative necessities.
        </p>
      </div>
    </div>
  );
}
